+/// Load workers from configuration file.
+///
+/// Returns an empty vector if no workers are configured. Does not print
+/// any messages - callers should handle the empty case appropriately.
+pub fn load_workers_from_config() -> Result<Vec<WorkerConfig>> {
+    let config_path = config_dir()
+        .map(|d| d.join("workers.toml"))
+        .context("Could not determine config directory")?;
+
+    if !config_path.exists() {
+        return Ok(vec![]);
+    }
+
+    let contents = std::fs::read_to_string(&config_path)
+        .with_context(|| format!("Failed to read {:?}", config_path))?;
+
+    // Parse the TOML - expect [[workers]] array
+    let parsed: toml::Value =
+        toml::from_str(&contents).with_context(|| format!("Failed to parse {:?}", config_path))?;
+
+    let empty_array = vec![];
+    let workers_array = parsed
+        .get("workers")
+        .and_then(|w| w.as_array())
+        .unwrap_or(&empty_array);
+
+    let mut workers = Vec::new();
+    for entry in workers_array {
+        let enabled = entry
+            .get("enabled")
+            .and_then(|v| v.as_bool())
+            .unwrap_or(true);
+        if !enabled {
+            continue;
+        }
+
+        let id = entry
+            .get("id")
+            .and_then(|v| v.as_str())
+            .unwrap_or("unknown");
+        let host = entry
+            .get("host")
+            .and_then(|v| v.as_str())
+            .unwrap_or("localhost");
+        let user = entry
+            .get("user")
+            .and_then(|v| v.as_str())
+            .unwrap_or("ubuntu");
+        let identity_file = entry
+            .get("identity_file")
+            .and_then(|v| v.as_str())
+            .unwrap_or("~/.ssh/id_rsa");
+        let total_slots = entry
+            .get("total_slots")
+            .and_then(|v| v.as_integer())
+            .unwrap_or(8) as u32;
+        let priority = entry
+            .get("priority")
+            .and_then(|v| v.as_integer())
+            .unwrap_or(100) as u32;
+        let tags: Vec<String> = entry
+            .get("tags")
+            .and_then(|v| v.as_array())
+            .map(|arr| {
+                arr.iter()
+                    .filter_map(|t| t.as_str().map(String::from))
+                    .collect()
+            })
+            .unwrap_or_default();
+
+        workers.push(WorkerConfig {
+            id: WorkerId::new(id),
+            host: host.to_string(),
+            user: user.to_string(),
+            identity_file: identity_file.to_string(),
+            total_slots,
+            priority,
+            tags,
+        });
+    }
+
+    Ok(workers)
+}
