+        .ok_or_else(|| anyhow::anyhow!("Invalid response format from daemon"))?;
+    let capabilities: WorkerCapabilitiesResponseFromApi =
+        serde_json::from_str(json).context("Failed to parse worker capabilities response")?;
+    Ok(capabilities)
